<script setup lang="ts">
const prefersMotion = !window.matchMedia(
  '(prefers-reduced-motion: reduce)'
).matches

const supportsWebGL = (() => {
  try {
    const canvas = document.createElement('canvas')
    return !!canvas.getContext('webgl2')
  } catch {
    return false
  }
})()
</script>
