  background: var(--surface-glass);
  backdrop-filter: blur(20px);
}
```

### ❌ DON'T: Ignore Information Density

```css
/* ❌ Wasted space */
.widget {
  padding: 48px;
  margin: 32px;
}

/* ✅ Appropriate density */
.widget {
  padding: var(--space-4);
  margin: var(--space-3);
}
```

### ❌ DON'T: Neglect Loading States

```jsx
/* ❌ No feedback */
{data && <Content data={data} />}

/* ✅ Complete states */
{loading && <Skeleton />}
{error && <ErrorMessage error={error} />}
{data && <Content data={data} />}
{!data && !loading && !error && <EmptyState />}
```

